import{_ as t,C as s,o,c as l,E as r,w as n,a,a0 as d}from"./chunks/framework.CkNTPv-z.js";const k=JSON.parse('{"title":"Sweden Legal Rights","description":"Legal rights for transgender people in Sweden","frontmatter":{"layout":"doc","title":"Sweden Legal Rights","description":"Legal rights for transgender people in Sweden"},"headers":[],"relativePath":"europe/sweden/legal-rights.md","filePath":"europe/sweden/legal-rights.md","lastUpdated":null}'),g={name:"europe/sweden/legal-rights.md"};function c(h,e,p,m,u,w){const i=s("Badge");return o(),l("div",null,[r(i,{variant:"yellow"},{default:n(()=>[...e[0]||(e[0]=[a("Self-ID since 2025",-1)])]),_:1}),r(i,{variant:"green"},{default:n(()=>[...e[1]||(e[1]=[a("Strong Anti-Discrimination Laws",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-sweden" tabindex="-1">Legal Rights in Sweden <a class="header-anchor" href="#legal-rights-in-sweden" aria-label="Permalink to &quot;Legal Rights in Sweden&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Sweden adopted a self-determination model for legal gender recognition through a new law that took effect in 2025. Previously, Sweden required a gender dysphoria diagnosis and a waiting period. The sterilisation requirement was removed in 2013.</p><p>The current (2025) process:</p><ul><li>Application to the <strong>Swedish Tax Agency (Skatteverket)</strong></li><li>No medical certificates or diagnosis required</li><li>No surgery requirement</li><li>No waiting period</li><li>For minors aged 12-17, application with parental consent and psychosocial support</li><li>Minors under 12 require special consideration with parental consent</li></ul><p>This reform was the result of many years of advocacy and represents a significant shift from Sweden&#39;s historically medicalised approach.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><p>Name changes can be submitted alongside the gender recognition application to Skatteverket. Sweden has a very permissive name change policy — any first name can be registered regardless of gender marker. For name-only changes (without gender marker change), an online application to Skatteverket is sufficient.</p><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Sweden has comprehensive anti-discrimination protections:</p><ul><li><strong>Discrimination Act (Diskrimineringslagen)</strong> — Explicitly prohibits discrimination based on gender identity and gender expression</li><li><strong>Employment</strong> — Full protection in all employment aspects</li><li><strong>Education</strong> — Protection in schools and universities</li><li><strong>Healthcare</strong> — Right to access care without discrimination</li><li><strong>Housing</strong> — Protection in rental and purchase</li><li><strong>Goods and services</strong> — Comprehensive protection</li></ul><p>The <strong>Equality Ombudsman (Diskrimineringsombudsmannen - DO)</strong> enforces discrimination laws.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Sweden&#39;s Penal Code (Brottsbalken) includes hate crime provisions with enhanced penalties for crimes motivated by a person&#39;s gender identity or gender expression. This covers:</p><ul><li>Violent crimes</li><li>Threats and harassment</li><li>Hate speech (hets mot folkgrupp)</li><li>Property crimes</li></ul><p>Swedish police have specialised hate crime units, and reporting mechanisms are well-established.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>Skatteverket</strong> — Gender recognition and name changes: <a href="https://www.skatteverket.se/" target="_blank" rel="noreferrer">skatteverket.se</a></li><li><strong>RFSL</strong> — Swedish LGBTQ+ rights organisation: <a href="https://www.rfsl.se/" target="_blank" rel="noreferrer">rfsl.se</a></li><li><strong>Diskrimineringsombudsmannen (DO)</strong> — <a href="https://www.do.se/" target="_blank" rel="noreferrer">do.se</a></li><li><strong>Transformering.se</strong> — Trans health and legal information: <a href="https://www.transformering.se/" target="_blank" rel="noreferrer">transformering.se</a></li><li><strong>ILGA-Europe - Sweden Country Report</strong> — <a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ilga-europe.org</a></li></ul>',18))])}const b=t(g,[["render",c]]);export{k as __pageData,b as default};
